#include <stdio.h>
#define MOD 10000000000007
int dp[1001][1001];
int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= K; j++) {
                for (int k = 1; k <= i; k++) {
                    if(j >= k) dp[i][j] = (dp[i][j] + dp[i-k][j-k]) % MOD;
                }
            }
        }
        int ans = 0;
        for (int i = 1; i <= K; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%d\n", ans);
    }
    return 0;
}

